"<script>\n"
"var map=null, mbToken='', demoMode=false, flights=[], selIcao=null, panelOn=true, markers={}, rfInt=null, radarA=0, RF=20000;\n"
"var currentFilter = {turkey:false, high:false, fast:false, search:''};\n"
"var trails = {}; var trailLayerId = 'trails'; var aircraftLayerId = 'aircraft';\n"
"var lastDataTime = 0;\n"
"var beepAudio = new Audio('data:audio/wav;base64,');\n"

"async function fetchOpenSky(){\n"
"  try{\n"
"    var r=await fetch('https://opensky-network.org/api/states/all?lamin=35.5&lomin=25.5&lamax=42.5&lomax=45.5',{signal:AbortSignal.timeout(14000)});\n"
"    if(!r.ok)throw 0;\n"
"    var d=await r.json();return d.states||[];\n"
"  }catch(e){\n"
"    try{\n"
"      var r2=await fetch('https://opensky-network.org/api/states/all',{signal:AbortSignal.timeout(14000)});\n"
"      var d2=await r2.json();return d2.states||[];\n"
"    }catch(e2){showNtf('OpenSky baglanamiyor - demo veri',true);return genDemo();}\n"
"  }\n"
"}\n"

"function parseS(s){\n"
"  return{icao24:s[0],callsign:(s[1]||'').trim()||s[0],country:s[2]||'?',lon:s[5],lat:s[6],\n"
"    alt:s[7]?Math.round(s[7]):null,ground:s[8],vel:s[9]?Math.round(s[9]*3.6):null,\n"
"    hdg:s[10]?Math.round(s[10]):null,sqk:s[14]||'?'};\n"
"}\n"

"function genDemo(){\n"
"  var al=['TK','LH','BA','AF','EK','QR','SU','PC','FR','W6'],\n"
"      co=['Turkey','Germany','UK','France','UAE','Qatar','Russia','USA','Spain'];\n"
"  return Array.from({length:80},function(_,i){\n"
"    return['dm'+i,al[i%al.length]+(100+i),co[i%co.length],null,null,\n"
"      15+Math.random()*45,33+Math.random()*28,2000+Math.random()*11000,\n"
"      false,200+Math.random()*700,Math.random()*360,null,null,null,\n"
"      Math.floor(1000+Math.random()*8999)];\n"
"  });\n"
"}\n"

"function initWithToken(){\n"
"  var v=document.getElementById('ti').value.trim();\n"
"  if(!v.startsWith('pk.')){showNtf('Gecersiz token!',true);return;}\n"
"  mbToken=v;localStorage.setItem('mbt',v);\n"
"  document.getElementById('tm').classList.add('hide');\n"
"  boot(false);\n"
"}\n"

"function initDemo(){demoMode=true;document.getElementById('tm').classList.add('hide');boot(true);}\n"

"async function boot(demo){\n"
"  var lb=document.getElementById('lb'),lt=document.getElementById('lt');\n"
"  var steps=[[20,'OPENSKY BAGLANTISI...'],[50,'HARITA YUKLENIYOR...'],[75,'VERI ALINIYOR...'],[90,'TRAIL & FILTRELER...'],[100,'HAZIR']];\n"
"  for(var i=0;i<steps.length;i++){\n"
"    lb.style.width=steps[i][0]+'%';lt.textContent=steps[i][1];\n"
"    await new Promise(function(r){setTimeout(r,380);});\n"
"  }\n"
"  await new Promise(function(r){setTimeout(r,250);});\n"
"  document.getElementById('ld').classList.add('hide');\n"
"  if(demo)initNoMap();else initMap();\n"
"  startRadar();startClock();loadFlights();startRfTimer();\n"
"  document.addEventListener('keydown',handleKey);\n"
"}\n"

"function startClock(){\n"
"  setInterval(function(){document.getElementById('clk').textContent=new Date().toTimeString().slice(0,8);},1000);\n"
"}\n"

"function initMap(){\n"
"  mapboxgl.accessToken=mbToken;\n"
"  map=new mapboxgl.Map({container:'map',style:'mapbox://styles/mapbox/satellite-v9',center:[32.8,39.5],zoom:5.5,antialias:true});\n"
"  map.addControl(new mapboxgl.NavigationControl({showCompass:true}),'top-right');\n"
"  map.on('load',function(){\n"
"    document.getElementById('sd').classList.remove('L');\n"
"    document.getElementById('st').textContent='CANLI';\n"
"    initLayers();\n"
"  });\n"
"  map.on('error',function(e){showNtf('Harita hatasi',true);});\n"
"}\n"

"function initNoMap(){\n"
"  var m=document.getElementById('map');\n"
"  m.style.background='radial-gradient(ellipse at 50% 50%,#020d1a 0%,#020810 100%)';\n"
"  var c=document.createElement('canvas');\n"
"  c.style.cssText='position:absolute;inset:0;width:100%;height:100%';\n"
"  m.appendChild(c);\n"
"  var ctx=c.getContext('2d');c.width=window.innerWidth;c.height=window.innerHeight;\n"
"  ctx.strokeStyle='rgba(0,255,136,.05)';ctx.lineWidth=1;\n"
"  for(var x=0;x<c.width;x+=55){ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x,c.height);ctx.stroke();}\n"
"  for(var y=0;y<c.height;y+=55){ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(c.width,y);ctx.stroke();}\n"
"  document.getElementById('sd').classList.remove('L');document.getElementById('st').textContent='DEMO';\n"
"}\n"

"function initLayers(){\n"
"  map.addSource(trailLayerId, {type:'geojson',data:{type:'FeatureCollection',features:[]}});\n"
"  map.addLayer({id: trailLayerId, type: 'line', source: trailLayerId, paint: {'line-color':'#00ff88','line-width':1.5,'line-opacity':0.35}});\n"
"  map.addSource(aircraftLayerId, {type:'geojson',data:{type:'FeatureCollection',features:[]}});\n"
"  map.addLayer({id: aircraftLayerId, type: 'symbol', source: aircraftLayerId, layout: {'icon-image': 'plane','icon-rotate': ['get', 'heading'],'icon-size': 0.8,'icon-allow-overlap': true}, paint: {'icon-color': ['case',['==',['get','selected'],true],'#00e5ff','#00ff88']}});\n"
"  var planeSVG = 'data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHZpZXdCb3g9IjAgMCAyNCAyNCI+PHBhdGggZD0iTTEyIDJMMCAxMEg0TDEwIDEyTDEyIDIwTDE0IDEyTDE4IDEwSDIyTDEyIDJaIiBmaWxsPSIjMDBmZjg4Ii8+PC9zdmc+';\n"
"  map.loadImage(planeSVG, function(err, image){if(!err) map.addImage('plane', image, {pixelRatio:2});});\n"
"}\n"

"var LS={satellite:'mapbox://styles/mapbox/satellite-v9',dark:'mapbox://styles/mapbox/dark-v11',street:'mapbox://styles/mapbox/streets-v12'};\n"

"function setLayer(l){\n"
"  if(demoMode||!map)return;\n"
"  ['satellite','dark','street'].forEach(function(x){document.getElementById('l'+x[0]+'b').classList.toggle('A',x===l);});\n"
"  map.setStyle(LS[l]);\n"
"  map.once('style.load',function(){initLayers();renderMarkers();});\n"
"  showNtf(l.toUpperCase()+' KATMANI');\n"
"}\n"

"async function loadFlights(){\n"
"  document.getElementById('sd').classList.add('L');\n"
"  var raw=await fetchOpenSky();\n"
"  flights=raw.map(parseS).filter(function(f){return f.lat&&f.lon&&!f.ground;});\n"
"  updateTrails();\n"
"  var trCount = flights.filter(f => f.country === \"Turkey\").length;\n"
"  document.getElementById('pc').textContent=flights.length;\n"
"  document.getElementById('trc').textContent=trCount;\n"
"  document.getElementById('lu').textContent=new Date().toTimeString().slice(0,5);\n"
"  document.getElementById('pct').textContent=flights.length;\n"
"  document.getElementById('sd').classList.remove('L');\n"
"  applyFilters();\n"
"  if(map)renderMarkers();\n"
"  lastDataTime = Date.now();\n"
"}\n"

"function updateTrails(){\n"
"  flights.forEach(function(f){\n"
"    if(!trails[f.icao24]) trails[f.icao24] = [];\n"
"    trails[f.icao24].push({lon:f.lon, lat:f.lat});\n"
"    if(trails[f.icao24].length > 12) trails[f.icao24].shift();\n"
"  });\n"
"}\n"

"function renderMarkers(){\n"
"  if(!map) return;\n"
"  var features = []; var trailFeatures = [];\n"
"  flights.forEach(function(f){\n"
"    var isSel = f.icao24 === selIcao;\n"
"    features.push({type:'Feature',geometry:{type:'Point',coordinates:[f.lon,f.lat]},properties:{icao:f.icao24, heading:f.hdg||0, selected:isSel}});\n"
"    if(trails[f.icao24] && trails[f.icao24].length > 1){\n"
"      trailFeatures.push({type:'Feature',geometry:{type:'LineString',coordinates:trails[f.icao24].map(p=>[p.lon,p.lat])},properties:{icao:f.icao24}});\n"
"    }\n"
"  });\n"
"  map.getSource(aircraftLayerId).setData({type:'FeatureCollection',features:features});\n"
"  map.getSource(trailLayerId).setData({type:'FeatureCollection',features:trailFeatures});\n"
"}\n"

"function renderList(filteredFlights){\n"
"  var fl=document.getElementById('fl');fl.innerHTML='';\n"
"  filteredFlights.slice(0,150).forEach(function(f){\n"
"    var d=document.createElement('div');\n"
"    d.className='fi'+(f.icao24===selIcao?' sel':'');\n"
"    d.innerHTML='<div class=\"fc\">'+f.callsign+'</div><div class=\"fd\"><span>'+f.country+'</span><span>'+(f.alt?f.alt+'m':'--')+'</span><span>'+(f.vel?f.vel+'km/s':'--')+'</span></div>';\n"
"    d.onclick=function(){selectFlight(f);};\n"
"    fl.appendChild(d);\n"
"  });\n"
"  if(filteredFlights.length===0) fl.innerHTML='<div style=\"padding:20px;text-align:center;color:rgba(168,255,212,.3);font-size:11px\">EŞLEŞEN UÇAK YOK</div>';\n"
"}\n"

"function applyFilters(){\n"
"  currentFilter.search = document.getElementById('search').value.toUpperCase().trim();\n"
"  var filtered = flights.filter(function(f){\n"
"    var matchSearch = !currentFilter.search || f.callsign.toUpperCase().includes(currentFilter.search);\n"
"    var matchTurkey = !currentFilter.turkey || f.country === 'Turkey';\n"
"    var matchHigh = !currentFilter.high || (f.alt && f.alt > 8000);\n"
"    var matchFast = !currentFilter.fast || (f.vel && f.vel > 700);\n"
"    return matchSearch && matchTurkey && matchHigh && matchFast;\n"
"  });\n"
"  renderList(filtered);\n"
"}\n"

"function toggleFilter(el){\n"
"  var id = el.id;\n"
"  if(id==='ftr') currentFilter.turkey = !currentFilter.turkey;\n"
"  if(id==='fhigh') currentFilter.high = !currentFilter.high;\n"
"  if(id==='ffast') currentFilter.fast = !currentFilter.fast;\n"
"  el.classList.toggle('active');\n"
"  applyFilters();\n"
"}\n"

"function selectFlight(f){\n"
"  selIcao = f.icao24;\n"
"  document.getElementById('ics').textContent = f.callsign;\n"
"  document.getElementById('ico').textContent = f.country;\n"
"  document.getElementById('ial').textContent = f.alt ? f.alt + ' m' : '---';\n"
"  document.getElementById('isp').textContent = f.vel ? f.vel + ' km/s' : '---';\n"
"  document.getElementById('ihe').textContent = f.hdg ? f.hdg + '°' : '---';\n"
"  document.getElementById('ila').textContent = f.lat.toFixed(4);\n"
"  document.getElementById('ilo').textContent = f.lon.toFixed(4);\n"
"  document.getElementById('isq').textContent = f.sqk;\n"
"  document.getElementById('ign').textContent = f.ground ? 'Yerde' : 'Havada';\n"
"  document.getElementById('ip').classList.add('vis');\n"
"  document.getElementById('hm').classList.add('vis');\n"
"  document.getElementById('ha').textContent = f.alt ? f.alt : '---';\n"
"  document.getElementById('hs').textContent = f.vel ? f.vel : '---';\n"
"  if(map) renderMarkers();\n"
"  applyFilters();\n"
"  if(f.country === 'Turkey' && f.alt && f.alt < 10000){beepAudio.currentTime = 0;beepAudio.play().catch(()=>{});}\n"
"}\n"

"function closeInfo(){\n"
"  document.getElementById('ip').classList.remove('vis');\n"
"  document.getElementById('hm').classList.remove('vis');\n"
"  selIcao = null;\n"
"  if(map) renderMarkers();\n"
"  applyFilters();\n"
"}\n"

"function openInFR24(){\n"
"  if(!selIcao) return;\n"
"  var callsign = document.getElementById('ics').textContent;\n"
"  window.open('https://www.flightradar24.com/' + callsign, '_blank');\n"
"}\n"

"function refreshData(){resetRfTimer();loadFlights();showNtf('VERI YENILENDI');}\n"

"function startRfTimer(){\n"
"  if(rfInt) clearInterval(rfInt);\n"
"  rfInt = setInterval(loadFlights, RF);\n"
"}\n"

"function resetRfTimer(){\n"
"  if(rfInt) clearInterval(rfInt);\n"
"  startRfTimer();\n"
"}\n"

"function startRadar(){\n"
"  var canvas = document.getElementById('rv'); var ctx = canvas.getContext('2d');\n"
"  function draw(){\n"
"    ctx.clearRect(0,0,96,96);\n"
"    ctx.strokeStyle = 'rgba(0,255,136,0.6)'; ctx.lineWidth = 2;\n"
"    for(var i=0;i<4;i++){ctx.beginPath();ctx.arc(48,48,12+i*18,0,Math.PI*2);ctx.stroke();}\n"
"    radarA = (radarA + 8) % 360;\n"
"    ctx.save(); ctx.translate(48,48); ctx.rotate(radarA * Math.PI / 180);\n"
"    ctx.strokeStyle = '#00ff88'; ctx.lineWidth = 3;\n"
"    ctx.beginPath(); ctx.moveTo(0,0); ctx.lineTo(40,0); ctx.stroke(); ctx.restore();\n"
"    requestAnimationFrame(draw);\n"
"  }\n"
"  draw();\n"
"}\n"

"function showNtf(txt,err){\n"
"  var n=document.getElementById('ntf');\n"
"  n.textContent=txt;\n"
"  if(err)n.classList.add('er');else n.classList.remove('er');\n"
"  n.classList.add('sh');\n"
"  setTimeout(function(){n.classList.remove('sh');},2200);\n"
"}\n"

"function togglePanel(){\n"
"  panelOn = !panelOn;\n"
"  document.getElementById('lp').classList.toggle('hide',!panelOn);\n"
"  document.getElementById('ptg').classList.toggle('hide',panelOn);\n"
"}\n"

"function handleKey(e){\n"
"  if(e.key === 'Escape') closeInfo();\n"
"  if(e.key.toLowerCase() === 'r') refreshData();\n"
"  if(e.key.toLowerCase() === 's') setLayer('satellite');\n"
"  if(e.key.toLowerCase() === 'd') setLayer('dark');\n"
"  if(e.key.toLowerCase() === 't') setLayer('street');\n"
"}\n"

"function toggleFullscreen(){\n"
"  if(!document.fullscreenElement) document.documentElement.requestFullscreen();\n"
"  else document.exitFullscreen();\n"
"}\n"
"</script>\n"
"</body>\n"
"</html>\n"
);

